#!/usr/bin/env bash
# esther-perel.sh — 长期关系维护 (Esther Perel 长期主义) SOP walkthrough for 恋爱高手.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="恋爱高手"
WORKFLOW="长期关系维护 (Esther Perel 长期主义)"

usage() {
  cat <<EOF
esther-perel.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./esther-perel.sh             # interactive
  ./esther-perel.sh --dry-run
  ./esther-perel.sh --json
  ./esther-perel.sh --explain
  ./esther-perel.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "长期关系维护 (Esther Perel 长期主义)" 工作流。

一句话: 长期关系最大挑战不是冲突, 是激情消退 + 现代关系压一个人需求过载.

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 健康关系不是没冲突, 是知道怎么修复 (核心 PASS): Gottman 30+ 年研究证明 — 婚姻稳定不取决于多吵架, 而取决于「修复尝试 (repair attempts)」是否被接受.
  • 亲密关系本质是依恋 (核心 PASS): 成人亲密关系 = 婴儿对父母的依恋, 都是「我有人吗?」的根本焦虑. 修复关系就是修复安全依恋.

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**理解长期关系悖论** (Esther Perel):"
  "**现代关系需求分散** (Esther Perel):"
  "**激情维护** (持续):"
  "**持续约会** (Gottman):"
  "**共同 + 独立的成长** (持续):"
)
declare -a FAILURE_MODES=(
  "把所有需求压伴侣 → 必然过载"
  "孩子 / 事业全占 → 夫妻关系沦为「合伙人」"
  "「我们再不像以前那样」 — 接受变化, 不要怀念过去"
  "蔑视长期累积 → 离婚预警"
  "不维护激情 → 7 年之痒不是必然, 但不维护就必然"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "esther-perel-walkthrough"
fi
